class SecureRotatingFileHandler(RotatingFileHandler):
    """RotatingFileHandler that sets file permissions on rotated files."""

    def __init__(self, *args, file_permission=0o640, **kwargs):
        self.file_permission = file_permission
        super().__init__(*args, **kwargs)
        self._set_permission()

    def _set_permission(self):
        if self.baseFilename and os.path.exists(self.baseFilename):
            os.chmod(self.baseFilename, self.file_permission)

    def doRollover(self):
        super().doRollover()
        self._set_permission()
        # Also fix permissions on rotated files
        for i in range(1, self.backupCount + 1):
            rotated = f"{self.baseFilename}.{i}"
            if os.path.exists(rotated):
                os.chmod(rotated, self.file_permission)


class SecureTimedRotatingFileHandler(TimedRotatingFileHandler):
    """TimedRotatingFileHandler that sets file permissions on rotated files."""

    def __init__(self, *args, file_permission=0o640, **kwargs):
        self.file_permission = file_permission
        super().__init__(*args, **kwargs)
        self._set_permission()

    def _set_permission(self):
        if self.baseFilename and os.path.exists(self.baseFilename):
            os.chmod(self.baseFilename, self.file_permission)

    def doRollover(self):
        super().doRollover()
        self._set_permission()
        # Fix permissions on rotated files
        log_dir = os.path.dirname(self.baseFilename)
        base_name = os.path.basename(self.baseFilename)
        for filename in os.listdir(log_dir):
            if filename.startswith(base_name) and filename != base_name:
                filepath = os.path.join(log_dir, filename)
                if os.path.exists(filepath):
                    os.chmod(filepath, self.file_permission)


